type LoginResponse = {
    data: LoginUserResponseInfo;
    pageBuildId: string;
};

const asyncSaveApiCache = async (axiosInstance: AxiosInstance, responseBody: LoginResponse) => {
    getSsDate().pageBuildId = responseBody.pageBuildId;
    getSsDate().user = responseBody.data;
    getSsDate().key = responseBody.data.key;
    //save to local
    if (isStaticPage()) {
        localStorage.setItem(ssKeyStorageKey, responseBody.data.key);
    }
    addToCache("/user", responseBody.data);

    const uris = responseBody.data.cacheableApiUris ?? [];

    const promises = uris.map(async (e) => {
        const key = e.split("/api/admin")[1];
        const { data } = await getCsrData(key, 0, axiosInstance);
        addToCache(key, data);
    });

    await Promise.all(promises)
        .then(() => {
            console.log("all api data cached");
        })
        .catch((error) => {
            console.error("cache error：", error);
        });
};

const Index = ({ offline }: { offline: boolean }) => {
    const [logging, setLogging] = useState<boolean>(false);
    const defaultUserInfo = getDefaultLoginInfo();
    const [loginState, setLoginState] = useState<LoginUserInfo>(defaultUserInfo);

    const [messageApi, contextHolder] = message.useMessage({ maxCount: 3 });

    const navigate = useNavigate();

    const { token } = theme.useToken();
    const axiosInstance = useAxiosBaseInstance();

    const onFinish = async () => {
        setLogging(true);
        const loginForm = {
            userName: loginState.userName,
            password: md5(loginState.password),
            https: window.location.protocol === "https:",
        };
        try {
            //set submit url
            if (isStaticPage()) {
                axiosInstance.defaults.baseURL = loginState.backendServerUrl;
            }
            const { data } = await axiosInstance.post("/api/admin/login", loginForm);
            if (data.error) {
                await messageApi.error(data.message);
                return;
            }
            if (data.error == 0) {
                //登录成功，保存网关地址
                if (isStaticPage() && loginState.backendServerUrl != null) {
                    setBackendServerUrl(loginState.backendServerUrl);
                }
                await asyncSaveApiCache(axiosInstance, data);
                const query = new URLSearchParams(window.location.search);
                const redirectFrom = query.get("redirectFrom") as string;
                if (redirectFrom !== null && redirectFrom !== "") {
                    const jumpTo = decodeURIComponent(redirectFrom);
                    //处理非 https iframe 跳转登录问题
                    if (jumpTo.startsWith(getContextPath() + "admin/plugins/")) {
                        window.location.href = window.location.protocol + "//" + window.location.host + jumpTo;
                    } else {
                        const newUrl = jumpTo.replace(getContextPath() + "admin", "");
                        const urlInfo = newUrl.split("?");
                        //默认首页
                        if (urlInfo[0] === "/" || urlInfo[0] === "") {
                            urlInfo[0] = "/index";
                        }
                        navigate(getRealRouteUrl(urlInfo.join("?")), { replace: true });
                    }
                } else {
                    navigate(getRealRouteUrl("/index"), { replace: true });
                }
                return;
            }
            await messageApi.error("未知错误");
        } finally {
            setLogging(false);
        }
    };

    useEffect(() => {
        removeAllCaches();
    }, []);

    return (
        <PWAHandler>
            {contextHolder}
            <StyledLoginPage
                mainColor={getAppState().colorPrimary}
                dark={getAppState().dark}
                colorBgContainer={token.colorBgContainer}
                colorBgLayout={token.colorBgLayout}
            >
                <div className={classes.container}>
                    <div className={classes.sideImage}>
                        <div className="side-content">
                            <h2>{getRes().websiteTitle}</h2>
                            <p>{getRes().copyrightCurrentYear}. All Rights Reserved.</p>
                        </div>
                    </div>
                    <div className={classes.formSection}>
                        <Title level={3} className={classes.title}>
                            {getRes().login}
                        </Title>
                        <div className="subtitle">{getRes().userNameAndPassword}</div>

                        <Form
                            layout="vertical"
                            initialValues={defaultUserInfo}
                            onFinish={() => onFinish()}
                            onValuesChange={(_k, v) => setLoginState(v)}
                        >
                            {isStaticPage() && (
                                <Form.Item
                                    label={getRes().backendServerUrl}
                                    name={"backendServerUrl"}
                                    rules={[{ required: true }]}
                                >
                                    <Input autoComplete={"url"} />
                                </Form.Item>
                            )}
                            <Form.Item label={getRes().userName} name="userName" rules={[{ required: true }]}>
                                <Input autoComplete={"username"} />
                            </Form.Item>

                            <Form.Item label={getRes().password} name="password" rules={[{ required: true }]}>
                                <Input.Password autoComplete={"current-password"} />
                            </Form.Item>

                            <Form.Item style={{ marginTop: "20px" }}>
                                <Button disabled={offline} loading={logging} type="primary" htmlType="submit">
                                    {getRes().login}
                                </Button>
                            </Form.Item>
                        </Form>
                    </div>
                </div>
            </StyledLoginPage>
        </PWAHandler>
    );
};

export default Index;
